const input = items[0].json;

// Hàm xóa icon và ký tự đặc biệt, chỉ giữ lại chữ, số và dấu câu cơ bản
const cleanText = (str) => {
  if (!str) return '';
  return str.toString()
    // Regex này giữ lại: Chữ cái (Tiếng Việt + Latin), Số, Khoảng trắng, và các dấu ( @ . , - _ : )
    // Các icon như ⌬, ∎, 🥷, 💧 sẽ bị loại bỏ hoàn toàn.
    .replace(/[^\w\s\dÀ-ỹ@.,\-_:()]/g, '')
    .trim();
};

let results = [];

// 1. Xử lý danh sách Admin
const adminContent =
  input.admins.map(a => 
  `- ${cleanText(a.first_name)} ${cleanText(a.last_name)} (@${cleanText(a.username || 'NA')}) - Vai tro: ${cleanText(a.role)}`
).join('\n');

results.push({ json: { type: 'Danh sách Admins', content: adminContent } });

// 2. Xử lý danh sách Ranking (Chia nhỏ mỗi 20 người)
const chunkSize = 23; 
for (let i = 0; i < input.ranking.length; i += chunkSize) {
  const chunk = input.ranking.slice(i, i + chunkSize);
  const part = Math.floor(i / chunkSize) + 1;

  const body = chunk.map(r => 
    `${r.rank}. ${cleanText(r.name)} (@${cleanText(r.username)}): ${r.message_count} tin`
  ).join('\n');

  results.push({ 
    json: { 
      type: `Danh sách User active nhất trong 1 tháng qua (P.${part})`, 
      content: body 
    } 
  });
}

return results;

const input = items[0].json;

// 3. Giữ nguyên danh sách tin nhắn (vì bạn muốn tách thành 3 items)
const topMessages = input.top_users_messages;

// Trả về 3 item riêng biệt cho n8n
return [
  { json: { type: 'messages', content: topMessages } }
];

